INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  '𝗖𝗔𝗠𝗣𝗔𝗠𝗘𝗡𝗧𝗢 𝗚𝗥𝗔𝗧𝗨𝗜𝗧𝗢 𝗙𝗜𝗡𝗔𝗟𝗘𝗦 𝗗𝗘 𝗝𝗨𝗡𝗜𝗢 𝗘𝗡 𝗟𝗨𝗗𝗢𝗧𝗘𝗖𝗔𝗦 𝗠𝗨𝗡𝗜𝗖𝗜𝗣𝗔𝗟𝗘𝗦 𝗬 𝗖𝗘𝗜𝗣 𝗙𝗘𝗟𝗜𝗖𝗜𝗔𝗡𝗢 𝗛𝗘𝗥𝗡𝗔́𝗡𝗗𝗘𝗭 𝗚𝗔𝗥𝗖𝗜́𝗔( 𝗗𝗘 𝟯 𝗔 𝟭𝟮 𝗔𝗡̃𝗢𝗦)',
  'El #AyuntamientoSDT con la idea de atender las necesidades de conciliación familiar y laboral de las familias tras la finalización del curso escolar va a realizar un 𝗖𝗮𝗺𝗽𝗮𝗺𝗲𝗻𝘁𝗼 𝗴𝗿𝗮𝘁𝘂𝗶𝘁𝗼 𝗮 𝗳𝗶𝗻𝗮𝗹𝗲𝘀 𝗱𝗲 𝗷𝘂𝗻𝗶𝗼, concretamente, del 22 al 30 de junio en las ludotecas municipales y en el CEIP Feliciano Hernández García. Está dirigido a niños y niñas empadronados y escolarizados en el municipio con edades comprendidas entre los 3 y los 12 años y se realizará en la Ludoteca Municipal La Cometa de Puerto de Santiago, en la Ludoteca Municipal La Bola de Cristal de Tamaimo y en el CEIP Feliciano Hernandez García de #SantiagodelTeide . 𝗛𝗼𝗿𝗮𝗿𝗶𝗼: 𝗗𝗲 𝟬𝟴:𝟬𝟬 𝗮 𝟭𝟲:𝟬𝟬𝗛. 𝗜𝗻𝗰𝗹𝘂𝘆𝗲 𝘀𝗲𝗿𝘃𝗶𝗰𝗶𝗼 𝗱𝗲 𝗰𝗼𝗺𝗲𝗱𝗼𝗿. 𝗣𝗹𝗮𝘇𝗮𝘀 𝗹𝗶𝗺𝗶𝘁𝗮𝗱𝗮𝘀. ¡No te quedes sin la tuya! Haz tu inscripción a través del QR de la publicación y/o en el siguiente enlace: https://forms.gle/DZBStDivEoKoYsGGA Para cualquier duda hay un teléfono de contacto que es el 922-02-93-64 y/o a través del correo electrónico: servicioscorresponsables@imagine50.org #SantiagodelTeide #ConstruyendoFuturo #AyuntamientoSDT #IgualdadSDT #CorresponsablesSDT',
  28.270699, -16.816467,
  'Santiago del Teide, Santiago del Teide',
  'culture',
