-- Visita del Papa a Tenerife [tribe:granadilla-abona:44590]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'Visita del Papa a Tenerife',
  'La Concejalía de Participación Ciudadana del Ayuntamiento de Granadilla de Abona, dirigida por la concejala Adaisy Arias Pérez, informa de la apertura del plazo de inscripción para la reserva de plazas en las guaguas municipales habilitadas, con motivo de la visita del Papa a Tenerife y la celebración de la misa prevista para el próximo 12 de junio de 2026 en Santa Cruz de Tenerife. Desde el área se habilitarán guaguas totalmente gratuitas para facilitar el desplazamiento de los vecinos del municipio al evento. Dichas inscripciones se realizarán de manera online ( www.granadilladeabona.org ) como a través de los SAC del municipio (con cita previa). Se tramitarán de manera conjunta como grupos organizados que se corresponderán a cada guagua, con el objetivo de facilitar la coordinación y aumentar las posibilidades de que los asistentes del municipio puedan permanecer ubicados juntos dentro del recinto del evento según la disponibilidad de la organización. Las salidas se realizarán a las 08:00 horas desde los siguientes puntos del municipio: •Granadilla casco — Parada del Mercadona de Granadilla casco •San Isidro — Ermita •El Médano — Plaza de la Ermita Se ruega a todos los asistentes estar en las paradas con al menos 15 minutos de antelación para garantizar una correcta organización y salida de las guaguas. El regreso está previsto aproximadamente a las 16:00 horas, una vez finalizado el evento y coordinada la salida de los grupos. Se recomienda a los asistentes acudir con: •Agua •Gorra •Calzado cómodo Asimismo, se solicita responsabilidad y compromiso con las plazas reservadas. En caso de no poder asistir finalmente, se ruega comunicarlo lo antes posible a través del correo electrónico: participacionciudadana@granadilladeabona.org Desde el Ayuntamiento de Granadilla de Abona se continúa trabajando para facilitar la participación vecinal en eventos de interés social y religioso, garantizando una organización eficiente y coordinada para todos los asistentes del municipio.',
  28.122031, -16.557315,
  'Granadilla de Abona, Granadilla de Abona',
  'art',
  '2026-06-12 18:00:00+00',
  '2026-06-12 20:00:00+00',
  team_id, 'upcoming', 'tribe:granadilla-abona:44590', '{}'
) ON CONFLICT (external_id) DO NOTHING;
