-- Taller » ¿ Conoces la I.A. ? « [tribe:granadilla-abona:44834]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'Taller » ¿ Conoces la I.A. ? «',
  'El Ilustre Ayuntamiento de Granadilla de Abona, a través de la Concejalía de Cultura y Fiestas, cuyo responsable es Carlos Abismael Díaz Barreto, invitan a la población a participar en el “ Taller ¿ Conoces la I.A. ? “ el miércoles 17 de junio a las 18:00 horas en el Salón de Actos del Convento de Granadilla de Abona. Esta actividad se encuentra dentro de la Agenda Cultural del 2º trimestre de 2026. » Taller ¿ Conoces la I.A. ?: La Inteligencia Artificial (IA)es un campo de la informática que desarrolla sistemas capaces de simular procesos cognitivos humanos, como el aprendizaje, el razonamiento, la percepción y la toma de decisiones. En lugar de seguir instrucciones rígidas, estas máquinas identifican patrones en grandes volúmenes de datos para resolver problemas de manera autónoma. La inteligencia artificial generativa, la más usada actualmente, es una rama de la inteligencia artificial que genera contenido automáticamente en respuesta a indicaciones escritas. El contenido generado puede incluir, entre otros, textos, código de software, imágenes, vídeos o música. En este taller conoceremos el modo en el que funciona la I.A., así como los patrones que utiliza para generar sus resultados de búsqueda, veremos ejemplos de programas que utilizan esta tecnología y daremos pautas para distinguir los contenidos que están realizados con Inteligencia Artificial de los que no. Actividad para jóvenes a partir de 11 años. Para participar en esta actividad es necesario inscribirse a través del siguiente ENLACE . Sólo es necesaria la inscripción del/ la joven que vaya a participar en la actividad. El plazo de inscripción es del 8 al 16 de junio. Las plazas son limitadas. Ven y participa en nuestras actividades. ¡Te esperamos !',
  28.122031, -16.557315,
  'Convento Franciscano de San Luis Obispo, Granadilla de Abona',
  'culture',
  '2026-06-17 17:00:00+00',
  '2026-06-17 20:00:00+00',
  team_id, 'upcoming', 'tribe:granadilla-abona:44834', ARRAY['https://www.granadilladeabona.org/wp-content/uploads/2026/06/CARTEL-IA-17-DE-JUNIO.jpg']::text[]
) ON CONFLICT (external_id) DO NOTHING;
