-- Ruta temática: Sonidos de antaño [tribe:granadilla-abona:44790]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'Ruta temática: Sonidos de antaño',
  'La Concejalía de Participación Ciudadana del Ayuntamiento de Granadilla de Abona, cuyo responsable es Adaisy Arias Pérez, organiza para el sábado, 20 de junio de 2026, la Ruta Temática “Los sonidos de antaño” en la que se se recorrerán las zonas menos transitadas del sur (Arona/Adeje), incluyendo el taller del silbo y lenguaje buciado, preservando de esta manera la comunicación que antaño se utilizaba en las islas y que se mantiene viva en La Gomera. Para participar en esta actividad la inscripción deberá realizarse en los SAC del municipio (con cita previa) del 8 al 12 de junio de 2026 y a través de la página web www.granadilladeabona.org . Las personas menores de edad deben ir acompañadas en todo momento por una persona familiar adulta como responsable. La recogida en las paradas establecidas tiene lugar a partir de las 8:00 horas y el regreso se estima a las 16:00 horas, aproximadamente. ¡Anímate y participa!',
