-- Teide – Altos de Guamaso [tribe:granadilla-abona:44792]
INSERT INTO public.events (id, title, description, lat, lng, place_name, category, start_time, end_time, creator_id, status, external_id, photos) VALUES (
  gen_random_uuid(),
  'Teide – Altos de Guamaso',
  'La Concejalía de Participación Ciudadana del Ayuntamiento de Granadilla de Abona, cuyo responsable es Adaisy Arias Pérez, organiza para el domingo, 21 de junio de 2026, la Ruta al Parque Nacional del Teide- Altos de Guamaso, en la que se realizará un recorrido circular de apenas 3 kilómetros, donde observar la flora de alta montaña canaria, además de las impresionantes vistas al norte de la isla y, si el clima lo permite, el mar de nubes y la isla de La Palma. Además, es un espacio que nos lleva a comentar sobre la cultura guanche por los tagorores actuales. Para participar en esta actividad la inscripción deberá realizarse en los SAC del municipio (con cita previa) del 8 al 12 de junio de 2026 y a través de la página web www.granadilladeabona.org. Las personas menores de edad deben ir acompañadas en todo momento por una persona familiar adulta como responsable. La recogida en las paradas establecidas tiene lugar a partir de las 8:00 horas y el regreso se estima a las 16:00 horas. ¡Anímate y participa! INFORMACIÓN IMPORTANTE: • Se deberá estar puntualmente desde las 8.00 en la parada elegida con el justificante de estar inscrito en la actividad, tanto suyo como de cada una de las personas que la acompañen, (bien en formato digital o en papel). • A las personas que tenían como parada el Cementerio de Granadilla, indicarles que tienen que estar en la Parada de guaguas de TITSA que hay junto a la estación de servicio de DISA, un poco más abajo de Mercadona. • No olvidar llevar calzado cómodo para caminar, así como ropa de abrigo o impermeable, gorra, comida y agua. • IMPORTANTE: Rogamos que aquellas personas que estén inscritas y finalmente no puedan participar, nos remitan email comunicando su baja al correo participacionciudadana@granadilladeabona.org , tres días antes de la finalización de la inscripción de la ruta correspondiente, antes de las 13.00 horas. • En caso de no comunicarlo o no asistir sin avisar, no podrán realizar la siguiente actividad de la Concejalía. • Reciban un cordial saludo.',
  28.122031, -16.557315,
  'Granadilla de Abona, Granadilla de Abona',
  'art',
  '2026-06-21 18:00:00+00',
  '2026-06-21 20:00:00+00',
  team_id, 'upcoming', 'tribe:granadilla-abona:44792', ARRAY['https://www.granadilladeabona.org/wp-content/uploads/2026/06/Teide-Altos-de-Guamaso-CARTEL.png']::text[]
) ON CONFLICT (external_id) DO NOTHING;
